/** Chars-per-token used by the estimate below. English-heavy text tokenizes
 * close to 4 chars/token with typical BPE tokenizers, but this app's chat
 * text is overwhelmingly Czech (diacritics, richer inflection â€” more
 * subword fragments per word), which measured consistently closer to
 * ~3.3 chars/token against real chat transcripts. Using 4 here systematically
 * undershoots the real prompt size, which matters because PromptBuilder's
 * budget trimming (and the memory panel's over-budget warning) both trust
 * this number â€” an undershoot means the trimmer stops cutting before the
 * prompt is actually back within the model's real context budget. */
const CHARS_PER_TOKEN = 3.3;

/** Shared rough token estimate used across the app (PromptBuilder, lorebook
 * activation budget, memory panel report). Pure, no DB/Tauri import â€” keeps
 * PromptBuilder unit-testable without booting the Tauri runtime (plan آ§6.2). */
export function estimateTokens(text: string): number {
  if (!text) return 0;
  return Math.ceil(text.length / CHARS_PER_TOKEN);
}

/** Pure vector helpers for the semantic memory layer â€” no DB/Tauri imports
 * so they're unit-testable. Vectors travel through SQLite as base64-encoded
 * little-endian f32 arrays (see migration 002). */

export function encodeVector(vec: number[] | Float32Array): string {
  const f32 = vec instanceof Float32Array ? vec : Float32Array.from(vec);
  const bytes = new Uint8Array(f32.buffer, f32.byteOffset, f32.byteLength);
  let binary = "";
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    binary += String.fromCharCode(...bytes.subarray(i, i + CHUNK));
  }
  return btoa(binary);
}

export function decodeVector(b64: string): Float32Array {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Float32Array(bytes.buffer);
}

/** Cosine similarity in [-1, 1]. Returns 0 for a dimension mismatch (e.g.
 * rows embedded by a different model) or a zero vector â€” such rows just
 * rank at the bottom instead of throwing. */
export function cosineSimilarity(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length || a.length === 0) return 0;
  let dot = 0;
  let normA = 0;
  let normB = 0;
  for (let i = 0; i < a.length; i++) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }
  if (normA === 0 || normB === 0) return 0;
  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

export type Provider = "openai" | "gemini" | "claude";

export interface ChatMessage {
  role: "system" | "user" | "assistant";
  content: string;
}

/** Mirrors the `connections` table row. The API key never lives here â€” it
 * stays in the OS keyring and is looked up by `id` on the Rust side. */
export interface ConnectionConfig {
  id: string;
  name: string;
  provider: Provider;
  baseUrl: string | null;
  model: string;
  temperature: number;
  topP: number;
  maxTokens: number;
  contextBudget: number;
  createdAt: string;
  updatedAt: string;
}

export type ConnectionDraft = Omit<ConnectionConfig, "id" | "createdAt" | "updatedAt">;

export interface ChatParams {
  temperature: number;
  topP: number;
  maxTokens: number;
}

/** Streaming events emitted by the future `chat_stream` command (M2). Kept
 * here now so the shape is settled ahead of time. */
export type StreamEvent =
  | { event: "Start" }
  | { event: "Token"; data: { text: string } }
  | { event: "Done"; data: { finish_reason: string } }
  | { event: "Error"; data: { message: string; retryable: boolean } };

