import { estimateTokens } from "./tokenEstimate";
import type { ConnectionConfig } from "../providers/types";

// Cache: model -> encoder instance
let tiktokenModule: any = null;
let tiktokenLoadAttempted = false;

async function ensureTiktoken(): Promise<any> {
  if (tiktokenModule) return tiktokenModule;
  if (tiktokenLoadAttempted) return null;
  tiktokenLoadAttempted = true;
  try {
    tiktokenModule = await import("tiktoken");
    return tiktokenModule;
  } catch {
    return null;
  }
}

// Simple string hash
function hashText(text: string): number {
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    const ch = text.charCodeAt(i);
    hash = ((hash << 5) - hash) + ch;
    hash |= 0;
  }
  return hash;
}

// Cache: "model:textHash" -> token count
const tokenCache = new Map<string, number>();
const MAX_CACHE_SIZE = 200;

function isOpenAIModel(model: string): boolean {
  return /^(gpt-|o1-|o3-)/.test(model);
}

export async function countTokens(
  model: string,
  text: string,
  connection?: ConnectionConfig,
): Promise<number> {
  if (!text) return 0;

  const cacheKey = `${model}:${hashText(text)}`;
  const cached = tokenCache.get(cacheKey);
  if (cached !== undefined) return cached;

  let tokens: number;

  if (isOpenAIModel(model)) {
    const tk = await ensureTiktoken();
    if (tk) {
      try {
        const enc = tk.encoding_for_model(model);
        tokens = enc.encode(text).length;
      } catch {
        tokens = estimateTokens(text);
      }
    } else {
      tokens = estimateTokens(text);
    }
  } else {
    // TODO: Gemini countTokens API & Anthropic token counting endpoint
    tokens = estimateTokens(text);
  }

  if (tokenCache.size >= MAX_CACHE_SIZE) {
    // Clear oldest entries (simple: just clear half)
    const keys = [...tokenCache.keys()].slice(0, Math.floor(MAX_CACHE_SIZE / 2));
    for (const k of keys) tokenCache.delete(k);
  }
  tokenCache.set(cacheKey, tokens);
  return tokens;
}

/**
 * Synchronous token count using a preloaded tiktoken module.
 * Falls back to estimateTokens if tiktoken is not loaded or the model is not OpenAI.
 * Call `countTokens` (async) to preload and populate the cache.
 */
export function syncCountTokens(model: string, text: string): number {
  if (!text) return 0;

  if (isOpenAIModel(model) && tiktokenModule) {
    try {
      const enc = tiktokenModule.encoding_for_model(model);
      return enc.encode(text).length;
    } catch {
      return estimateTokens(text);
    }
  }

  return estimateTokens(text);
}

/** Preload tiktoken for future syncCountTokens calls. Safe to call multiple times. */
export async function preloadTokenCounter(): Promise<void> {
  await ensureTiktoken();
}
```

