```typescript
function selectDiverseFacts(
  facts: LedgerFactLike[],
  relevance: Record<string, number>,
  factVectors: Record<string, number[]>,
  k: number,
  lambda: number,
): LedgerFactLike[] {
  if (k >= facts.length) return [...facts];
  if (k <= 0) return [];

  const selected: LedgerFactLike[] = [];
  const remaining = [...facts];

  // Convert vectors to Float32Array for cosineSimilarity
  const vectors = new Map<string, Float32Array>();
  for (const [id, vec] of Object.entries(factVectors)) {
    vectors.set(id, Float32Array.from(vec));
  }

  // First: pick the most relevant fact
  // Sort by relevance, pick top
  remaining.sort((a, b) => {
    const ra = relevance[a.id] ?? 0;
    const rb = relevance[b.id] ?? 0;
    return rb - ra;
  });

  // Pick first
  const first = remaining.shift()!;
  selected.push(first);

  // Then: iteratively pick remaining using MMR
  while (selected.length < k && remaining.length > 0) {
    let bestIdx = 0;
    let bestScore = -Infinity;

    const selVecs = selected.map(s => vectors.get(s.id)).filter(Boolean) as Float32Array[];

    for (let i = 0; i < remaining.length; i++) {
      const f = remaining[i];
      const rel = relevance[f.id] ?? 0;
      const fVec = vectors.get(f.id);

      let maxSim = 0;
      if (fVec && selVecs.length > 0) {
        for (const sv of selVecs) {
          const sim = cosineSimilarity(fVec, sv);
          if (sim > maxSim) maxSim = sim;
        }
      }

      const mmr = lambda * rel - (1 - lambda) * maxSim;
      if (mmr > bestScore) {
        bestScore = mmr;
        bestIdx = i;
      }
    }

    const [next] = remaining.splice(bestIdx, 1);
    selected.push(next);
  }

  return selected;
}
```

