  it("selectDiverseFacts picks diverse topics â€” character fact survives over redundant location facts", () => {
    // Three event facts: two about location (nearly identical vectors),
    // one about a character (orthogonal vector).  With MMR and k=2, the
    // character fact MUST be in the selected set even though its raw
