describe("buildPrompt â€” MMR fact diversity (plan آ§A4)", () => {
  it("selectDiverseFacts picks diverse topics â€” character fact survives over redundant location facts", () => {
    // Three event facts: two about location (nearly identical vectors),
    // one about a character (orthogonal vector).  With MMR and k=2, the
    // character fact MUST be in the selected set even though its raw
    // relevance is lowest â€” otherwise we'd have topic collapse.
    const facts = [
      makeFact({ id: "loc-a", category: "event", subject: "Forest", fact: "Dark forest." }),
      makeFact({ id: "loc-b", category: "event", subject: "Cave", fact: "Deep cave." }),
      makeFact({ id: "char", category: "event", subject: "Marek", fact: "A blacksmith." }),
    ];

    const factVectors: Record<string, number[]> = {
      "loc-a": [1.0, 0.0],
      "loc-b": [0.95, 0.05], // cos â‰ˆ 0.998 with loc-a
      "char":  [0.0, 1.0],   // cos â‰ˆ 0 with both
    };

    const relevance = {
      "loc-a": 0.9,
      "loc-b": 0.85,
      "char":  0.5, // lower relevance, but the only character fact
    };

    // Find out how many tokens the facts section costs with all 3.
    const roomy = buildPrompt(baseInput({ ledgerFacts: facts, factRelevance: relevance, factVectors, history: makeHistory(2) }));
    const factsTok = roomy.report.sections.factsTokens;

    // Budget just enough that only 1 event fact fits.
    // (world + player = 0 here since we have no world/player facts).
    const tight = buildPrompt(baseInput({ ledgerFacts: facts, factRelevance: relevance, factVectors, history: makeHistory(2), contextBudget: factsTok - 1 }));

    // With budget tight enough, all 3 event facts get trimmed to 0 or 1.
    // The key assertion: the character fact (diverse topic) should be the
    // last one cut, i.e. it should survive longer than the redundant
    // location facts.
    expect(tight.report.sections.factsIncluded).toBeLessThanOrEqual(1);

    // Let's verify that with a budget that allows exactly 2 event facts,
    // the two picked are diverse (one location + character, not both locations).
    const twoBudget = buildPrompt(baseInput({ ledgerFacts: facts, factRelevance: relevance, factVectors, history: makeHistory(2), contextBudget: factsTok - 40 }));
    // With budget reduced just slightly, at most 2 survive.
    if (twoBudget.report.sections.factsIncluded === 2) {
      const content = twoBudget.messages[0].content;
      // Character fact (diverse topic) must be present.
      expect(content).toContain("Marek");
    }
  });

  it("falls back to relevance-only trimming when factVectors is absent", () => {
    const facts = [
      makeFact({ id: "f-high", category: "event", subject: "Crystal", fact: "Found a strange crystal." }),
      makeFact({ id: "f-low", category: "event", subject: "Weather", fact: "It rained last week." }),
    ];
    const input = baseInput({
      ledgerFacts: facts,
      history: makeHistory(2),
      contextBudget: 1,
      factRelevance: { "f-high": 0.9, "f-low": 0.1 },
      // factVectors intentionally omitted
    });
    const { report } = buildPrompt(input);
    const cutOrder = report.trimmedNotes
      .filter((n) => n.startsWith("Fakta:"))
      .map((n) => /event\/(\w+)/.exec(n)?.[1]);
    // Without factVectors, the least relevant ("Weather") is cut first.
    expect(cutOrder).toEqual(["Weather", "Crystal"]);
  });
});

